function slugify(input) {
  return String(input || "")
    .trim()
    .toLowerCase()
    .replace(/['"]/g, "")
    .replace(/\s+/g, "-")
    .replace(/[^a-z0-9\-_]+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "");
}

function extractTags(str) {
  const s = String(str || "").trim();
  if (!s) return [];

  // Try hashtags first: "#n8n #wordpress"
  const hashMatches = s.match(/#[^\s#,;]+/g) || [];
  let raw = hashMatches.map(t => t.replace(/^#+/, "").trim()).filter(Boolean);

  // If no #tags found, fallback to splitting words
  if (raw.length === 0) {
    raw = s
      .split(/[\s,;]+/g)
      .map(t => t.replace(/^#+/, "").trim())
      .filter(Boolean);
  }

  // Clean trailing punctuation
  raw = raw.map(t => t.replace(/[^\w\-]+$/g, "").trim()).filter(Boolean);

  // Deduplicate by slug
  const seen = new Set();
  const out = [];

  for (const name of raw) {
    const slug = slugify(name);
    if (!slug) continue;
    if (seen.has(slug)) continue;
    seen.add(slug);
    out.push({ tag_name: name, tag_slug: slug });
  }

  return out;
}

