const data = $getWorkflowStaticData('global');
const wpTagIds = String(data.wp_tag_ids || '0');

const tags = wpTagIds
  .split(',')
  .map(s => parseInt(s.trim(), 10))
  .filter(n => Number.isFinite(n) && n > 0);

// Текущая строка поста из основного цикла
const row = $node["Loop Over Items"].json;

// 1) media_id, если ты его уже сохранил в item (лучший вариант)
let mediaId = Number.isFinite(row.media_id) ? row.media_id : null;

// 2) fallback: попробовать взять id из ноды Upload $image to WP,
//    но БЕЗОПАСНО — эта нода может не выполняться.
if (!Number.isFinite(mediaId)) {
  try {
    const uploadItems = $items("Upload $image to WP"); // может бросить, если нода не выполнялась
    const uploadId = uploadItems?.[0]?.json?.id;
    if (Number.isFinite(uploadId)) {
      mediaId = uploadId;
    }
  } catch (e) {
    // upload node not executed -> ignore
  }
}

// Собираем payload для WP
const payload = {
  title: row.title || '',
  excerpt: row.excerpt || '',
  content: row.body || '',
  status: row.post_status || '',
  tags,
};

// Добавляем featured_media только если есть корректный id
if (Number.isFinite(mediaId) && mediaId > 0) {
  payload.featured_media = mediaId;
}

return [{
  json: {
    ...row,
    wp_post_payload: payload,
  }
}];

const data = $getWorkflowStaticData('global');

const nextId = $json.id; // или $json.tag_id — что у тебя реально является ID
const idStr = String(nextId || '').trim();

if (/^\d+$/.test(idStr)) {
  const current = String(data.wp_tag_ids || '0');
  const parts = current.split(',').map(s => s.trim()).filter(Boolean);

  // без дублей
  if (!parts.includes(idStr)) {
    data.wp_tag_ids = current + ',' + idStr;
  }
}

return items;

